class EpisodicMemoryBuffer:
    def __init__(self, capacity: int):
        if capacity < 1:
            raise ValueError('capacity must be >= 1')
        self.capacity = capacity
        self._buffer = []

    def store(self, memory: dict) -> bool:
        evicted = False
        if len(self._buffer) >= self.capacity:
            # Evict lowest priority
            min_idx = min(range(len(self._buffer)), key=lambda i: self._buffer[i]['priority'])
            self._buffer.pop(min_idx)
            evicted = True
        self._buffer.append(dict(memory))
        return evicted

    def retrieve_all(self) -> list:
        return sorted(self._buffer, key=lambda m: -m['priority'])

    def update_priority(self, idx: int, new_priority: float):
        if idx < 0 or idx >= len(self._buffer):
            raise IndexError(f'Buffer index {idx} out of range')
        self._buffer[idx]['priority'] = new_priority

    def size(self) -> int:
        return len(self._buffer)

